ALTER TABLE squads ADD COLUMN IF NOT EXISTS timezone TEXT DEFAULT 'UTC';

DROP FUNCTION IF EXISTS calculate_squad_leaderboard(UUID, DATE, DATE);

CREATE FUNCTION calculate_squad_leaderboard(target_squad_id UUID, start_date DATE, end_date DATE) RETURNS TABLE(user_id UUID, name TEXT, total_score BIGINT, habit_completions BIGINT, perfect_days BIGINT, calorie_hits BIGINT, workout_completions BIGINT, trifecta_days BIGINT, reactions_given BIGINT) LANGUAGE plpgsql AS 'BEGIN RETURN QUERY WITH members AS (SELECT sm.user_id, u.name FROM squad_members sm JOIN users u ON u.id = sm.user_id WHERE sm.squad_id = target_squad_id), habits AS (SELECT sf.user_id, COUNT(*) AS cnt FROM squad_feed sf WHERE sf.squad_id = target_squad_id AND sf.event_type = ''habit_completed'' AND sf.created_at::date BETWEEN start_date AND end_date GROUP BY sf.user_id), perfects AS (SELECT sf.user_id, COUNT(*) AS cnt FROM squad_feed sf WHERE sf.squad_id = target_squad_id AND sf.event_type = ''perfect_day'' AND sf.created_at::date BETWEEN start_date AND end_date GROUP BY sf.user_id), calories AS (SELECT sf.user_id, COUNT(*) AS cnt FROM squad_feed sf WHERE sf.squad_id = target_squad_id AND sf.event_type = ''calorie_target_hit'' AND sf.created_at::date BETWEEN start_date AND end_date GROUP BY sf.user_id), workouts AS (SELECT sf.user_id, COUNT(*) AS cnt FROM squad_feed sf WHERE sf.squad_id = target_squad_id AND sf.event_type = ''workout_completed'' AND sf.created_at::date BETWEEN start_date AND end_date GROUP BY sf.user_id), trifecta AS (SELECT sub.user_id, COUNT(*) AS cnt FROM (SELECT sf.user_id, sf.created_at::date AS day FROM squad_feed sf WHERE sf.squad_id = target_squad_id AND sf.event_type IN (''perfect_day'',''calorie_target_hit'',''workout_completed'') AND sf.created_at::date BETWEEN start_date AND end_date GROUP BY sf.user_id, sf.created_at::date HAVING COUNT(DISTINCT sf.event_type) = 3) sub GROUP BY sub.user_id), reactions AS (SELECT sr.user_id, COUNT(*) AS cnt FROM squad_reactions sr JOIN squad_feed sf ON sf.id = sr.feed_id WHERE sf.squad_id = target_squad_id AND sr.created_at::date BETWEEN start_date AND end_date GROUP BY sr.user_id) SELECT m.user_id, m.name, (COALESCE(h.cnt,0)*5+COALESCE(p.cnt,0)*25+COALESCE(c.cnt,0)*50+COALESCE(w.cnt,0)*50+COALESCE(t.cnt,0)*10+COALESCE(r.cnt,0)*2)::BIGINT AS total_score, COALESCE(h.cnt,0)::BIGINT AS habit_completions, COALESCE(p.cnt,0)::BIGINT AS perfect_days, COALESCE(c.cnt,0)::BIGINT AS calorie_hits, COALESCE(w.cnt,0)::BIGINT AS workout_completions, COALESCE(t.cnt,0)::BIGINT AS trifecta_days, COALESCE(r.cnt,0)::BIGINT AS reactions_given FROM members m LEFT JOIN habits h ON h.user_id=m.user_id LEFT JOIN perfects p ON p.user_id=m.user_id LEFT JOIN calories c ON c.user_id=m.user_id LEFT JOIN workouts w ON w.user_id=m.user_id LEFT JOIN trifecta t ON t.user_id=m.user_id LEFT JOIN reactions r ON r.user_id=m.user_id ORDER BY total_score DESC; END;';
